#include <iostream>
#include <unordered_map>
#include <cstring>
#include <cstdlib>
#include <arpa/inet.h>
#include <sys/socket.h>
#include <unistd.h>

// Packet types
enum PacketType : uint8_t {
    POSITION_UPDATE = 1,
    SHOOT = 2
};

// Data structures for packets (packed)
#pragma pack(push, 1)
struct PositionPacket {
    uint8_t type;       // should be POSITION_UPDATE
    uint32_t playerId;
    float x, y, z;
};

struct ShootPacket {
    uint8_t type;       // should be SHOOT
    uint32_t playerId;
    // Player position when shooting (could be used for hit detection)
    float x, y, z;
    // Direction of the shot
    float dx, dy, dz;
};
#pragma pack(pop)

struct PlayerState {
    float x, y, z;
};

std::unordered_map<uint32_t, PlayerState> playerStates;

void processPositionPacket(const PositionPacket &packet) {
    // Update the player's position (no validation)
    playerStates[ntohl(packet.playerId)] = {packet.x, packet.y, packet.z};
    std::cout << "Player " << ntohl(packet.playerId) 
              << " updated position to (" << packet.x << ", " 
              << packet.y << ", " << packet.z << ")\n";
}

void processShootPacket(const ShootPacket &packet) {
    // Process shooting – here, simply output the shoot event
    uint32_t pid = ntohl(packet.playerId);
    std::cout << "Player " << pid << " shot from (" << packet.x << ", " 
              << packet.y << ", " << packet.z << ") in direction (" 
              << packet.dx << ", " << packet.dy << ", " << packet.dz << ")\n";
    // In a real game, you would check for hits here, etc.
}

int main() {
    // Create a UDP socket
    int sockfd = socket(AF_INET, SOCK_DGRAM, 0);
    if (sockfd < 0) {
        std::perror("socket");
        std::exit(EXIT_FAILURE);
    }

    // Bind the socket to an address and port
    sockaddr_in serverAddr;
    std::memset(&serverAddr, 0, sizeof(serverAddr));
    serverAddr.sin_family = AF_INET;
    serverAddr.sin_addr.s_addr = INADDR_ANY;
    const int port = 9000;
    serverAddr.sin_port = htons(port);

    if (bind(sockfd, (sockaddr*)&serverAddr, sizeof(serverAddr)) < 0) {
        std::perror("bind");
        close(sockfd);
        std::exit(EXIT_FAILURE);
    }

    std::cout << "UDP game server running on port " << port << "\n";

    // Buffer big enough to hold the largest packet
    const size_t bufferSize = 1024;
    char buffer[bufferSize];

    while (true) {
        sockaddr_in clientAddr;
        socklen_t addrLen = sizeof(clientAddr);
        ssize_t recvLen = recvfrom(sockfd, buffer, bufferSize, 0,
                                   (sockaddr*)&clientAddr, &addrLen);
        if (recvLen < 0) {
            std::perror("recvfrom");
            continue;
        }
        if (recvLen < 1) continue; // At least one byte for type

        uint8_t packetType = static_cast<uint8_t>(buffer[0]);
        if (packetType == POSITION_UPDATE) {
            if (static_cast<size_t>(recvLen) < sizeof(PositionPacket)) continue;
            PositionPacket posPacket;
            std::memcpy(&posPacket, buffer, sizeof(PositionPacket));
            processPositionPacket(posPacket);
        } else if (packetType == SHOOT) {
            if (static_cast<size_t>(recvLen) < sizeof(ShootPacket)) continue;
            ShootPacket shootPacket;
            std::memcpy(&shootPacket, buffer, sizeof(ShootPacket));
            processShootPacket(shootPacket);
        } else {
            std::cout << "Unknown packet type received: " << static_cast<int>(packetType) << "\n";
        }
    }
    
    close(sockfd);
    return 0;
}